import{_ as t,a,b as r,c as d,d as o,e as l,f as n}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as i,o as s,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Discord Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/discord.md","filePath":"my/upload/discord.md","lastUpdated":1781962217000}'),p={name:"my/upload/discord.md"};function b(g,e,m,u,D,v){return s(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="discord-channel-ထည့်သွင်းခြင်း" tabindex="-1">Discord Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#discord-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;Discord Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>အသုံးပြုပုံ</th></tr></thead><tbody><tr><td>Discord account</td><td>server, channel, developer application ဖန်တီးရန်။</td></tr><tr><td>Discord server</td><td>bot က channel ကို access မလုပ်ခင် server ထဲဝင်ထားရမည်။</td></tr><tr><td>Text channel</td><td>images နဲ့ files တွေကို ဒီ channel ဆီပို့ပါမယ်။</td></tr><tr><td>Discord Developer Portal</td><td>application ဖန်တီးရန်၊ bot ဖန်တီးရန်၊ <code>Bot Token</code> ရယူရန်။</td></tr></tbody></table><h2 id="ဘယ်နေရာမှာ-ထည့်မလဲ" tabindex="-1">ဘယ်နေရာမှာ ထည့်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-ထည့်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ ထည့်မလဲ&quot;">​</a></h2><ol><li>System Settings ကိုဖွင့်ပါ။</li><li>Upload Settings ကိုသွားပါ။</li><li>ညာဘက်အပေါ်ထောင့်က Add Channel ကိုနှိပ်ပါ။</li><li><code>Discord</code> ကိုရွေးပါ။</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>အသုံးပြုပုံ</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ဒီ channel အတွက် မှတ်မိလွယ်တဲ့အမည်၊ ဥပမာ <code>Discord Primary</code>။</td><td>Required</td></tr><tr><td>Bot Token</td><td>Discord bot token။</td><td>Required</td></tr><tr><td>Channel ID</td><td>target text channel ရဲ့ ID။</td><td>Required</td></tr><tr><td>Proxy URL (optional)</td><td>Discord CDN access မတည်ငြိမ်လျှင်သာသုံးပါ။ <code>https://</code> ပါတဲ့ full URL ထည့်ပါ။</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-discord-server-နဲ့-text-channel-ဖန်တီးပါ" tabindex="-1">1. Discord Server နဲ့ Text Channel ဖန်တီးပါ <a class="header-anchor" href="#_1-discord-server-နဲ့-text-channel-ဖန်တီးပါ" aria-label="Permalink to &quot;1. Discord Server နဲ့ Text Channel ဖန်တီးပါ&quot;">​</a></h3><ol><li>Discord ကိုဖွင့်ပါ။</li><li>server အသစ်ဖန်တီးပါ၊ သို့မဟုတ် သင်ပိုင်တဲ့ existing server ကိုသုံးပါ။</li><li>အဲဒီ server ထဲမှာ text channel တစ်ခုဖန်တီးပါ။</li></ol><p><img src="'+t+'" alt="Create a server" loading="lazy"></p><h3 id="_2-discord-developer-portal-မှာ-bot-ဖန်တီးပါ" tabindex="-1">2. Discord Developer Portal မှာ Bot ဖန်တီးပါ <a class="header-anchor" href="#_2-discord-developer-portal-မှာ-bot-ဖန်တီးပါ" aria-label="Permalink to &quot;2. Discord Developer Portal မှာ Bot ဖန်တီးပါ&quot;">​</a></h3><ol><li>Discord Developer Portal ကိုဖွင့်ပါ: <code>https://discord.com/developers/applications</code></li><li><code>New Application</code> ကိုနှိပ်ပါ။</li><li>application name ထည့်ပြီး create လုပ်ပါ။</li><li>left sidebar မှ <code>Bot</code> page ကိုဖွင့်ပါ။</li><li><code>Bot</code> page မှာ token ကို generate သို့မဟုတ် reset လုပ်ပါ။</li><li>token ကိုသိမ်းပါ။</li></ol><p>ဒီ token က ImgBed မှာထည့်ရမယ့် <code>Bot Token</code> ဖြစ်ပါတယ်။</p><p><img src="'+a+'" alt="View the bot token" loading="lazy"></p><h3 id="_3-oauth2-invite-link-ဖန်တီးပြီး-bot-install-လုပ်ပါ" tabindex="-1">3. OAuth2 Invite Link ဖန်တီးပြီး Bot Install လုပ်ပါ <a class="header-anchor" href="#_3-oauth2-invite-link-ဖန်တီးပြီး-bot-install-လုပ်ပါ" aria-label="Permalink to &quot;3. OAuth2 Invite Link ဖန်တီးပြီး Bot Install လုပ်ပါ&quot;">​</a></h3><ol><li>left sidebar မှ <code>OAuth2</code> page ကိုဖွင့်ပါ။</li><li>scopes အောက်မှာ <code>bot</code> ကိုရွေးပါ။</li><li>permission area မှာ ဒီ permissions တွေကို enable လုပ်ပါ:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Required</th></tr></thead><tbody><tr><td>View Channels</td><td>Yes</td></tr><tr><td>Send Messages</td><td>Yes</td></tr><tr><td>Attach Files</td><td>Yes</td></tr><tr><td>Read Message History</td><td>Yes</td></tr></tbody></table><ol start="4"><li>page အောက်မှာ integration type က <code>Guild Install</code> ဖြစ်ကြောင်း confirm လုပ်ပါ။</li><li>generated URL ကို copy လုပ်ပါ။</li><li>အဲဒီ URL ကို browser မှာဖွင့်ပါ။</li><li>target server ကိုရွေးပါ။</li><li>authorization flow ကိုပြီးအောင်လုပ်ပါ။</li></ol><p><img src="'+r+'" alt="Select bot permissions in OAuth2" loading="lazy"></p><p><img src="'+d+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-developer-mode-enable-လုပ်ပြီး-channel-id-copy-လုပ်ပါ" tabindex="-1">4. Developer Mode Enable လုပ်ပြီး Channel ID Copy လုပ်ပါ <a class="header-anchor" href="#_4-developer-mode-enable-လုပ်ပြီး-channel-id-copy-လုပ်ပါ" aria-label="Permalink to &quot;4. Developer Mode Enable လုပ်ပြီး Channel ID Copy လုပ်ပါ&quot;">​</a></h3><ol><li>Discord ရဲ့ ဘယ်ဘက်အောက်ထောင့် avatar အနားက gear icon ကိုနှိပ်ပါ။</li><li>left sidebar မှ Advanced ကိုဖွင့်ပါ။</li><li>Developer Mode ကို enable လုပ်ပါ။</li><li>target text channel ကိုပြန်သွားပါ။</li><li>channel name ပေါ် right-click လုပ်ပါ။</li><li>Copy Channel ID ကိုနှိပ်ပါ။</li></ol><p>copy လုပ်ထားတဲ့ number က ImgBed မှာလိုအပ်တဲ့ <code>Channel ID</code> ဖြစ်ပါတယ်။</p><p><img src="'+o+'" alt="Enable developer mode" loading="lazy"></p><p><img src="'+l+'" alt="Copy the channel ID" loading="lazy"></p><h3 id="_5-imgbed-မှာ-discord-channel-ဖြည့်ပါ" tabindex="-1">5. ImgBed မှာ Discord Channel ဖြည့်ပါ <a class="header-anchor" href="#_5-imgbed-မှာ-discord-channel-ဖြည့်ပါ" aria-label="Permalink to &quot;5. ImgBed မှာ Discord Channel ဖြည့်ပါ&quot;">​</a></h3><p>channel configuration dialog ကိုပြန်သွားပြီး:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel name</td><td>custom channel name၊ ဥပမာ <code>DiscordPrimary</code>။</td></tr><tr><td>Bot Token</td><td>Discord Developer Portal ရဲ့ <code>Bot</code> page မှသိမ်းထားတဲ့ token။</td></tr><tr><td>Channel ID</td><td>Discord မှ copy လုပ်ထားတဲ့ channel ID။</td></tr><tr><td>Proxy URL (optional)</td><td>လိုအပ်မှသာ၊ ဥပမာ <code>https://your-proxy.example.com</code>။</td></tr></tbody></table><p>ပြီးရင် Save ကိုနှိပ်ပါ။</p><p><img src="'+n+`" alt="Add the Discord channel configuration" loading="lazy"></p><h2 id="စစ်ဆေးနည်း" tabindex="-1">စစ်ဆေးနည်း <a class="header-anchor" href="#စစ်ဆေးနည်း" aria-label="Permalink to &quot;စစ်ဆေးနည်း&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>စစ်ဆေးပုံ</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save ပြီးနောက် Upload Settings page မှာ Discord channel card ပေါ်လာရပါမယ်။</td></tr><tr><td>Channel can be enabled</td><td>Active switch က on ဖြစ်ရပါမယ်။</td></tr><tr><td>Configuration is saved</td><td>detail view မှာ Bot Token နဲ့ Channel ID သိမ်းထားတာမြင်ရပါမယ်။</td></tr><tr><td>Upload works</td><td>test image upload လုပ်ပြီး target Discord text channel ထဲပေါ်လာလားစစ်ပါ။</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Discord server ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; text channel ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; Discord Developer Portal မှာ bot ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; Bot page မှ Bot Token သိမ်းပါ</span></span>
<span class="line"><span>-&gt; OAuth2 မှာ bot, View Channels, Send Messages, Attach Files, Read Message History ရွေးပါ</span></span>
<span class="line"><span>-&gt; generated URL ကို copy လုပ်ပြီး target server အတွက် bot ကို authorize လုပ်ပါ</span></span>
<span class="line"><span>-&gt; target text channel မှာ permissions တူညီလားစစ်ပါ</span></span>
<span class="line"><span>-&gt; Developer Mode enable လုပ်ပါ</span></span>
<span class="line"><span>-&gt; target text channel ပေါ် right-click လုပ်ပြီး Channel ID copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed မှာ Bot Token နဲ့ Channel ID ထည့်ပါ</span></span>
<span class="line"><span>-&gt; Save လုပ်ပြီး test image upload လုပ်ပါ</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const y=i(p,[["render",b]]);export{_ as __pageData,y as default};
